// PARSE MESSAGE — Evolution API webhook
// Suporta: texto, áudio (ogg/ptt), imagem, documento/PDF, vídeo
const body = $input.first().json.body || $input.first().json;

if (body.data?.key?.fromMe === true) return [];
const event = body.event || '';
if (event && !event.includes('messages')) return [];

const instance = body.instance || body.instanceName || '';
const remoteJid = body.data?.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net','').replace('@g.us','').replace(/\D/g,'');
if (remoteJid.includes('@g.us')) return [];

const messageType = body.data?.messageType || 'conversation';
const message = body.data?.message || {};

// Texto
let text = message.conversation || message.extendedTextMessage?.text
  || message.imageMessage?.caption || message.videoMessage?.caption
  || message.documentMessage?.caption || '';

// Mídia
let media_type = null, media_base64 = null, media_mimetype = null;
if (messageType === 'audioMessage' || messageType === 'pttMessage') {
  media_type = 'audio';
  media_base64 = message.audioMessage?.base64 || message.pttMessage?.base64 || null;
  media_mimetype = message.audioMessage?.mimetype || 'audio/ogg; codecs=opus';
} else if (messageType === 'imageMessage') {
  media_type = 'image';
  media_base64 = message.imageMessage?.base64 || null;
  media_mimetype = message.imageMessage?.mimetype || 'image/jpeg';
} else if (messageType === 'documentMessage') {
  media_type = 'document';
  media_base64 = message.documentMessage?.base64 || null;
  media_mimetype = message.documentMessage?.mimetype || 'application/pdf';
} else if (messageType === 'videoMessage') {
  media_type = 'video';
  media_base64 = message.videoMessage?.base64 || null;
  media_mimetype = message.videoMessage?.mimetype || 'video/mp4';
}

if (!text && !media_type) return [];

return [{ json: { instance, phone, remoteJid, text: text || '', media_type, media_base64, media_mimetype, messageType, timestamp: new Date().toISOString() } }];

const result = $('Find User').first().json;
const users = Array.isArray(result) ? result : [result];
const phone = $('Parse Message').first().json.phone;
const instance = $('Parse Message').first().json.instance;
if (!users.length || !users[0]?.user_id) return [{ json: { error: true, message: 'Sem usuário para: ' + instance } }];
const u = users[0];
if (u.active === false) return [{ json: { error: true, message: 'Usuário desativado' } }];
return [{ json: { error: false, user_id: u.user_id, display_name: u.display_name, evo_instance: u.evo_instance, phone, instance } }];

// Combina sub + lead + detecta tipo de agente
const subRaw = $('Get Subscription').first().json;
const leadRaw = $('Find or Create Lead').first().json;
const userData = $('Validate User').first().json;
const sub = (Array.isArray(subRaw) ? subRaw[0] : subRaw) || {};
const lead = (Array.isArray(leadRaw) ? leadRaw[0] : leadRaw) || {};
const stage = lead.stage || 'novo_contato';
const fluxo_id = lead.fluxo_id || '';
const objecoes_count = lead.objecoes_count || 0;
let agent_type = 'principal', agent_index = 0;
if ((stage === 'objecoes' || objecoes_count > 2) && sub.addon_objecao) agent_type = 'objecao';
else if (stage === 'prospecao' || fluxo_id.includes?.('prospec')) agent_type = 'prospec';
else if (sub.agentes_extras > 0 && fluxo_id.match?.(/ae(\d)/)) { agent_type = 'extra'; agent_index = parseInt(fluxo_id.match(/ae(\d)/)[1]); }
return [{ json: { user_id: userData.user_id, lead_id: lead.lead_id, lead_nome: lead.nome, is_new_lead: lead.is_new || false, stage, agent_type, agent_index, evo_instance: userData.evo_instance, phone: userData.phone, creditos: sub.creditos_tokens || 0 } }];

// Resolve o texto final: transcrição/descrição OU texto original
const parsed = $('Parse Message').first().json;
const media_type = parsed.media_type;
let final_text = parsed.text || '';
const hasMedia = media_type !== null && media_type !== undefined && parsed.media_base64 !== null;

if (hasMedia) {
  try {
    const api = $('Process Media').first().json;
    const result = api.text || api.content || '';
    if (result) {
      if (media_type === 'audio') final_text = result;
      else if (media_type === 'image') final_text = (final_text ? final_text + '\n\n' : '') + '[Imagem]\n' + result;
      else if (media_type === 'document') final_text = (final_text ? final_text + '\n\n' : '') + '[PDF/Documento]\n' + result;
      else final_text = (final_text ? final_text + '\n\n' : '') + '[Vídeo] ' + result;
    } else {
      const label = { audio: '[Áudio não transcrito]', image: '[Imagem recebida]', document: '[Documento recebido]', video: '[Vídeo recebido]' };
      final_text = (final_text || '') + (label[media_type] || '[Mídia recebida]');
    }
  } catch(e) { final_text = final_text || '[Mídia recebida]'; }
}

return [{ json: { final_text: final_text || '[mensagem vazia]', media_type } }];

// BUILD PROMPT — configs + histórico + mensagem (texto ou mídia transcrita)
const configRaw = $('Get Configs').first().json;
const configs = Array.isArray(configRaw) ? configRaw : [];
const cm = {};
configs.forEach(i => { if (i.chave && i.valor !== undefined) cm[i.chave] = i.valor; });

const ag = $('Process Data').first().json;
const px = ag.agent_type === 'principal' ? '' : ag.agent_type === 'prospec' ? 'prospec_' : ag.agent_type === 'objecao' ? 'ob_' : `ae${ag.agent_index}_`;
const cfg = (k, fb) => cm[`${px}${k}`] || cm[k] || fb || '';

// Prompt base
let prompt = cfg('sistema_prompt', 'Você é um assistente de vendas profissional. Qualifique leads com base nos critérios definidos. Seja educado, persuasivo e objetivo.');
const obj = cfg('objetivo'); if (obj) prompt = `OBJETIVO: ${obj}\n\n${prompt}`;
const ton = cfg('tonalidade'); if (ton) prompt += `\n\nTONALIDADE: ${ton}`;
const crit = cfg('criterios_qualificacao'); if (crit) prompt += `\n\nCRITÉRIOS DE QUALIFICAÇÃO:\n${crit}`;
const inst = cfg('instrucoes_comunicacao'); if (inst) prompt += `\n\nINSTRUÇÕES DE COMUNICAÇÃO:\n${inst}`;
prompt += '\n\nTAGS ESPECIAIS:\n- [LEAD_QUALIFICADO] — quando o lead atende todos os critérios\n- [LEAD_DESQUALIFICADO] — quando não tem perfil\n- [INICIAR_PAGAMENTO] — quando quer pagar\n\nIMPORTANTE: Mensagens curtas e naturais como WhatsApp. Máximo 3 parágrafos.';

// Provider / modelo
const provider = cfg('ai_provider', 'openai');
let model = 'gpt-4o-mini', temperature = 0.7, max_tokens = 1024;
if (provider === 'claude') { model = cfg('claude_model','claude-haiku-4-5'); temperature = parseFloat(cfg('claude_temperature','0.7')); max_tokens = parseInt(cfg('claude_max_tokens','1024')); }
else if (provider === 'google') { model = cfg('google_model','gemini-2.0-flash'); temperature = parseFloat(cfg('google_temperature','0.7')); max_tokens = parseInt(cfg('google_max_tokens','1024')); }
else { model = cfg('openai_model','gpt-4o-mini'); temperature = parseFloat(cfg('openai_temperature','0.7')); max_tokens = parseInt(cfg('openai_max_tokens','1024')); }

// Histórico
const hist = Array.isArray($('Get History').first().json) ? $('Get History').first().json : [];
const messages = [{ role: 'system', content: prompt }];
[...hist].reverse().forEach(m => messages.push({ role: m.sender === 'assistant' ? 'assistant' : 'user', content: m.conteudo }));

// Texto final (transcrito se era áudio/imagem, ou texto direto)
const final_text = $('Resolve Text').first().json.final_text;
messages.push({ role: 'user', content: final_text });

return [{ json: {
  provider, model, temperature, max_tokens, messages, user_id: ag.user_id,
  msg_qualificado: cfg('msg_qualificado','Parabéns! Você foi qualificado.'),
  msg_desqualificado: cfg('msg_desqualificado','Obrigado pelo contato!'),
  responder_em_audio: cfg('responder_em_audio','false'),
  numero_destino: cfg('numero_destino'),
  notif_destino: cm['notif_destino'] || 'numero'
} }];

// PROCESS RESPONSE — detecta qualificação, objeções, limpa tags
const llm = $('LLM Call').first().json;
const response = llm.content || llm.choices?.[0]?.message?.content || '';
const promptData = $('Build Prompt').first().json;
const userText = ($('Resolve Text').first().json.final_text || '').toLowerCase();
const ag = $('Process Data').first().json;

const qualified = response.includes('[LEAD_QUALIFICADO]');
const disqualified = response.includes('[LEAD_DESQUALIFICADO]');
const payment = response.includes('[INICIAR_PAGAMENTO]');

const objWords = ['não posso','muito caro','não sei','concorrente','depois','não tenho','sem interesse','tá caro','está caro'];
let has_objection = false, objection_type = '';
for (const kw of objWords) {
  if (userText.includes(kw)) {
    has_objection = true;
    objection_type = kw.includes('caro') || kw.includes('não tenho') ? 'preco' : kw.includes('depois') ? 'timing' : kw.includes('concorrente') ? 'concorrente' : 'outro';
    break;
  }
}

let clean = response.replace(/\[LEAD_QUALIFICADO\]/g,'').replace(/\[LEAD_DESQUALIFICADO\]/g,'').replace(/\[INICIAR_PAGAMENTO\]/g,'').trim();

let new_stage = ag.stage;
if (qualified) new_stage = 'qualificado';
else if (disqualified) new_stage = 'nao_qualificado';
else if (ag.stage === 'novo_contato') new_stage = 'em_atendimento';

return [{ json: {
  response_text: clean, qualified, disqualified, payment_intent: payment,
  has_objection, objection_type, new_stage,
  tokens_used: llm.deducted_tokens || 0,
  responder_em_audio: promptData.responder_em_audio === 'true',
  numero_destino: promptData.numero_destino,
  notif_destino: promptData.notif_destino
} }];
